parameters.jsCode:
// Parse booking data from Google Calendar or scheduling widget
const body = $input.first().json.body || $input.first().json;

const prospectEmail = body.email || body.attendee_email;
const callDate = body.start_time || body.scheduled_date;
const prospectName = body.name || `${body.first_name || ''} ${body.last_name || ''}`.trim();

if (!prospectEmail || !callDate) {
  throw new Error('Missing required booking data: email and start_time');
}

// Format date in EST
const estDate = new Date(callDate).toLocaleString('en-US', {
  timeZone: 'America/New_York',
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  hour: 'numeric',
  minute: '2-digit',
  hour12: true
});

return [{
  json: {
    prospect_email: prospectEmail,
    prospect_name: prospectName,
    prospect_phone: body.phone || '',
    call_date_iso: callDate,
    call_date_est: estDate,
    program_interest: body.program_interest || '',
    duration_minutes: body.duration || 30
  }
}];

