parameters.jsCode:
const zoom = $input.first().json;
const prev = $('Parse Booking Data').first().json;

return [{
  json: {
    ...prev,
    zoom_meeting_id: String(zoom.id),
    zoom_join_url: zoom.join_url,
    zoom_start_url: zoom.start_url,
    zoom_password: zoom.password || ''
  }
}];

