parameters.jsonBody:
={{ JSON.stringify({
  summary: `Discovery Call — ${$json.prospect_name}`,
  description: `Prospect: ${$json.prospect_name}\nEmail: ${$json.prospect_email}\nPhone: ${$json.prospect_phone}\nProgram: ${$json.program_interest}\n\nZoom: ${$json.zoom_join_url}`,
  start: {
    dateTime: $json.call_date_iso,
    timeZone: 'America/New_York'
  },
  end: {
    dateTime: new Date(new Date($json.call_date_iso).getTime() + $json.duration_minutes * 60000).toISOString(),
    timeZone: 'America/New_York'
  },
  attendees: [
    { email: $json.prospect_email }
  ],
  conferenceData: {
    entryPoints: [{
      entryPointType: 'video',
      uri: $json.zoom_join_url,
      label: 'Zoom Meeting'
    }]
  },
  reminders: {
    useDefault: false,
    overrides: [
      { method: 'email', minutes: 60 },
      { method: 'popup', minutes: 15 }
    ]
  }
}) }}

parameters.responseBody:
